## 1️⃣ Webhook Stripe – Production ready

### a. Code (branch `backend‑final‑s0`, commit `feat:webhook‑prod`)

```ts
// src/webhooks/stripe.webhook.controller.ts
import {
  Controller,
  Post,
  Headers,
  Body,
  Req,
  Res,
  HttpStatus,
} from '@nestjs/common';
import { Request, Response } from 'express';
import Stripe from 'stripe';
import { SupabaseService } from '../supabase/supabase.service';
import { OrdersService } from '../orders/orders.service';
import { loadStripeSecrets } from '../common/utils/secret-manager';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY, {
  apiVersion: '2023-08-16',
});

@Controller('webhooks')
export class StripeWebhookController {
  constructor(
    private readonly ordersService: OrdersService,
    private readonly supabase: SupabaseService,
  ) {}

  @Post('stripe')
  async handle(@Req() req: Request, @Res() res: Response, @Headers('stripe-signature') sig: string) {
    const payload = req.rawBody; // rawBody middleware in main.ts
    const { stripeWebhookSecret } = await loadStripeSecrets(); // ← secret manager
    let event: Stripe.Event;

    try {
      event = stripe.webhooks.constructEvent(payload, sig, stripeWebhookSecret);
    } catch (err) {
      console.error('⚠️  Stripe signature verification failed', err);
      return res.status(HttpStatus.BAD_REQUEST).send('Invalid signature');
    }

    // Idempotence – check stripe_events table first
    const exists = await this.supabase
      .from('stripe_events')
      .select('event_id')
      .eq('event_id', event.id)
      .single();

    if (exists.data) {
      // déjà traité
      return res.status(HttpStatus.OK).send('Event already processed');
    }

    // Persist event id
    await this.supabase.from('stripe_events').insert({
      event_id: event.id,
      type: event.type,
      created_at: new Date(),
    });

    // Process only the intents we care about
    if (event.type === 'payment_intent.succeeded') {
      const pi = event.data.object as Stripe.PaymentIntent;
      const orderId = pi.metadata?.orderId;
      if (orderId) {
        await this.ordersService.updateStatus(orderId, 'paid');
        await this.publishOrderUpdate(orderId, 'paid');
      }
    } else if (event.type === 'payment_intent.payment_failed') {
      const pi = event.data.object as Stripe.PaymentIntent;
      const orderId = pi.metadata?.orderId;
      if (orderId) {
        await this.ordersService.updateStatus(orderId, 'failed');
        await this.publishOrderUpdate(orderId, 'failed');
      }
    }

    return res.status(HttpStatus.OK).send('Webhook processed');
  }

  private async publishOrderUpdate(orderId: string, status: string) {
    // Supabase Realtime publish – channel “orders”
    await this.supabase
      .from('orders')
      .update({ status })
      .eq('id', orderId);
    // No extra code needed – Supabase automatically pushes UPDATE events
  }
}
```

- **Idempotence** : table `stripe_events` empêche le double‑traitement.  
- **Secret Manager** : `loadStripeSecrets()` lit `stripe_webhook_secret_test` (ou la version live).  
- **Realtime** : mise à jour `orders` déclenche automatiquement un événement `UPDATE` sur le canal `orders`.  

